            {cart.map(item => (
              <div key={item.id} className="bg-white p-4 rounded-2xl border border-slate-100 flex items-center gap-4 shadow-sm">
                <img src={item.imageUrl} alt={item.name} className="w-20 h-20 rounded-xl object-cover" />
                <div className="flex-1">
                  <h3 className="font-bold text-slate-800">{item.name}</h3>
                  <p className="text-sm text-slate-400">R$ {item.price.toFixed(2)} / {item.unit}</p>
                </div>
                <div className="flex items-center gap-3 bg-slate-50 p-1 rounded-xl">
                  <button 
                    onClick={() => updateQuantity(item.id, -1)}
                    className="w-8 h-8 flex items-center justify-center text-slate-500 hover:text-emerald-600 hover:bg-white rounded-lg transition-all"
                  >
                    <Minus size={16} />
                  </button>
                  <span className="w-8 text-center font-bold text-slate-700">{item.quantity}</span>
                  <button 
                    onClick={() => updateQuantity(item.id, 1)}
                    className="w-8 h-8 flex items-center justify-center text-slate-500 hover:text-emerald-600 hover:bg-white rounded-lg transition-all"
                  >
                    <Plus size={16} />
                  </button>
                </div>
                <button 
                  onClick={() => removeFromCart(item.id)}
                  className="p-2 text-slate-300 hover:text-red-500 hover:bg-red-50 rounded-lg transition-colors"
                >
                  <Trash2 size={18} />
                </button>
              </div>
            ))}

            {/* AI Assistant Hook */}
            <div className="bg-emerald-50 rounded-2xl p-6 border border-emerald-100">
              <div className="flex items-center gap-3 mb-4">
                <div className="w-10 h-10 bg-emerald-600 text-white rounded-xl flex items-center justify-center shadow-lg shadow-emerald-200">
                  <Sparkles size={20} />
                </div>
                <div>
                  <h4 className="font-bold text-emerald-900">Assistente Smart Horti</h4>
                  <p className="text-sm text-emerald-700">Sugestão de receita com base no seu carrinho</p>
                </div>
              </div>

              {aiSuggestion ? (
                <div className="bg-white/60 backdrop-blur p-4 rounded-xl border border-emerald-200 text-sm text-emerald-800 animate-in fade-in slide-in-from-bottom-2 duration-500 whitespace-pre-wrap">
                  {aiSuggestion}
                  <button 
                    onClick={() => setAiSuggestion(null)} 
                    className="block mt-4 text-xs font-bold uppercase tracking-wider text-emerald-600 hover:text-emerald-800"
                  >
                    Limpar Sugestão
                  </button>
                </div>
              ) : (
                <button 
                  onClick={fetchAiRecipe}
                  disabled={isLoading}
                  className="w-full py-3 bg-emerald-600 text-white rounded-xl font-bold hover:bg-emerald-700 transition-colors disabled:opacity-50"
                >
                  {isLoading ? 'Pensando em uma receita...' : 'Gerar Receita Saudável'}
                </button>
              )}
            </div>
          </div>

          <div className="space-y-6">
            <div className="bg-white p-6 rounded-3xl border border-slate-100 shadow-xl">
              <h2 className="text-xl font-bold text-slate-800 mb-6">Resumo</h2>
              <div className="space-y-4 text-sm mb-6">
                <div className="flex justify-between text-slate-600">
                  <span>Subtotal</span>
                  <span className="font-semibold">R$ {cartTotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-slate-600">
                  <span>Entrega</span>
                  <span className={shipping === 0 ? "text-emerald-600 font-bold" : "font-semibold"}>
                    {shipping === 0 ? "Grátis" : `R$ ${shipping.toFixed(2)}`}
                  </span>
                </div>
                {appliedCoupon && (
                  <div className="flex justify-between text-emerald-600 font-medium">
                    <span>Cupom (10%)</span>
                    <span>- R$ {discount.toFixed(2)}</span>
                  </div>
                )}
                <div className="pt-4 border-t border-slate-100 flex justify-between items-center">
                  <span className="text-base font-bold text-slate-800">Total</span>
                  <span className="text-2xl font-black text-emerald-700">R$ {finalTotal.toFixed(2)}</span>
                </div>
              </div>

              <div className="space-y-3">
                <button 
                  onClick={() => setView('checkout')}
                  className="w-full py-4 bg-emerald-600 text-white rounded-2xl font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-200 hover:scale-[1.02] active:scale-95"
                >
                  Finalizar Compra
                </button>
                <button 
                  onClick={() => setView('home')}
                  className="w-full py-4 bg-slate-50 text-slate-600 rounded-2xl font-bold hover:bg-slate-100 transition-all"
                >
                  Continuar Comprando
                </button>
              </div>
            </div>

            <div className="bg-emerald-50 p-6 rounded-2xl border border-emerald-100">
              <div className="flex items-center gap-2 text-emerald-700 font-bold mb-2">
                <Tags size={18} />
                <span>Tem um cupom?</span>
              </div>
              <div className="flex gap-2">
                <input 
                  type="text" 
                  placeholder="Código"
                  className="flex-1 px-4 py-2 bg-white border border-emerald-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-emerald-500"
                />
                <button 
                  onClick={() => setAppliedCoupon('BEMVINDO10')}
                  className="px-4 py-2 bg-emerald-600 text-white rounded-xl font-bold text-xs"
                >
                  Aplicar
                </button>
              </div>
            </div>
          </div>
