// --- Sub-components (Scoped Helpers) ---

const LoadingOverlay = () => (
  <div className="fixed inset-0 bg-white/80 backdrop-blur-sm z-50 flex items-center justify-center">
    <div className="animate-spin rounded-full h-12 w-12 border-t-2 border-b-2 border-emerald-600"></div>
  </div>
);

// --- Main App Component ---

export default function App() {
  // State
  const [view, setView] = useState<'home' | 'cart' | 'checkout' | 'admin' | 'orders' | 'profile' | 'login' | 'payment-qr'>('home');
  const [products, setProducts] = useState<Product[]>(INITIAL_PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [currentUser, setCurrentUser] = useState<User | null>(null);
  const [orders, setOrders] = useState<Order[]>([]);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [appliedCoupon, setAppliedCoupon] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [aiSuggestion, setAiSuggestion] = useState<string | null>(null);

  // Checkout State
  const [deliveryType, setDeliveryType] = useState<'delivery' | 'pickup'>('delivery');
  const [lastOrder, setLastOrder] = useState<Order | null>(null);
  const [address, setAddress] = useState<Address>({
    fullName: '',
    street: '',
    number: '',
    neighborhood: '',
    city: '',
    state: '',
    zipCode: ''
  });

  // Derived State
  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase());
      const matchesCategory = selectedCategory === 'all' || p.category === selectedCategory;
      return matchesSearch && matchesCategory;
    });
  }, [products, searchTerm, selectedCategory]);

  const cartTotal = cart.reduce((acc, item) => acc + item.price * item.quantity, 0);
  const discount = appliedCoupon ? (cartTotal * 0.1) : 0; 
  const shipping = (deliveryType === 'pickup' || cartTotal >= FREE_SHIPPING_THRESHOLD) ? 0 : SHIPPING_RATE;
  const finalTotal = cartTotal - discount + shipping;

  // Handlers
  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (id: string) => {
    setCart(prev => prev.filter(item => item.id !== id));
  };

  const updateQuantity = (id: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === id) {
        const newQty = Math.max(1, item.quantity + delta);
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const validateAddress = () => {
    if (deliveryType === 'pickup') return true;
    return address.fullName && address.street && address.number && address.neighborhood && address.city && address.state;
  };

  const handlePlaceOrder = () => {
    if (!currentUser) {
      setView('login');
      return;
    }

    if (!validateAddress()) {
      alert('Por favor, preencha todos os campos do endereço de entrega.');
      return;
    }

    setIsLoading(true);
    setTimeout(() => {
      const newOrder: Order = {
        id: `ORD-${Math.random().toString(36).substr(2, 9).toUpperCase()}`,
        userId: currentUser.id,
        items: [...cart],
        total: finalTotal,
        status: 'pending',
        date: new Date().toISOString(),
        paymentMethod: 'pix',
        deliveryType,
        address: deliveryType === 'delivery' ? address : undefined,
      };

      setLastOrder(newOrder);
      setOrders([newOrder, ...orders]);
      setCart([]);
      setAppliedCoupon(null);
      setIsLoading(false);
      setView('payment-qr');
    }, 1200);
  };

  const handleLogin = (role: 'customer' | 'admin') => {
    setIsLoading(true);
    setTimeout(() => {
      setCurrentUser({
        id: 'user-1',
        name: role === 'admin' ? 'Administrador' : 'João Silva',
        email: role === 'admin' ? 'admin@hortifresh.com' : 'joao@email.com',
        role: role,
      });
      setAddress(prev => ({ ...prev, fullName: role === 'admin' ? 'Administrador' : 'João Silva' }));
      setIsLoading(false);
      setView('home');
    }, 800);
  };

  const fetchAiRecipe = async () => {
    setIsLoading(true);
    const suggestion = await getSmartRecipeSuggestions(cart);
    setAiSuggestion(suggestion);
    setIsLoading(false);
  };

  // --- Views ---

  const renderHeader = () => (
    <header className="sticky top-0 z-40 bg-white border-b border-slate-100 shadow-sm">
      <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
        <div className="flex items-center gap-2 cursor-pointer" onClick={() => setView('home')}>
          <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center text-white shadow-lg shadow-emerald-200">
            <ShoppingBasket size={24} />
          </div>
          <span className="text-xl font-bold bg-gradient-to-r from-emerald-600 to-lime-600 bg-clip-text text-transparent hidden sm:block">
